const COLOR_PALETTE = ['#6b43ef', '#2f74ef', '#18a88a', '#f08a24', '#e84b72', '#8a5cf6', '#0ea5e9', '#d946ef', '#64748b'];

function dimension(key, label, title, summary, strengths = [], growth = []) {
  return { key, label, title, summary, strengths, growth };
}

function q(dimensionKey, text, reverse = false) {
  return { dimension: dimensionKey, text, reverse };
}

function buildTest(config) {
  return {
    answerLabels: ['Strongly Disagree', 'Disagree', 'Neutral', 'Agree', 'Strongly Agree'],
    ...config,
    dimensions: config.dimensions.map((item, index) => ({ ...item, color: item.color || COLOR_PALETTE[index % COLOR_PALETTE.length] })),
    questions: config.questions.map((question, index) => ({ ...question, id: `${config.slug}-${index + 1}` })),
  };
}

