function compactDimension([key, label, title, summary, strengths, growth]) {
  return dimension(key, label, title, summary, strengths, growth);
}

function buildCompactTest({ slug, title, category = 'Popular', time = '6 min', intro, notice, dimensions, questions }) {
  return buildTest({
    slug,
    title,
    category,
    time,
    intro,
    notice,
    dimensions: dimensions.map(compactDimension),
    questions: questions.flatMap(([dimensionKey, ...items]) =>
      items.map((item) => (Array.isArray(item) ? q(dimensionKey, item[0], Boolean(item[1])) : q(dimensionKey, item))),
    ),
  });
}

